#[derive(Debug, Clone, PartialEq, Eq)]
pub struct OrderLine {
    pub sku: String,
    pub quantity: u32,
}

#[derive(Debug, Clone, PartialEq, Eq)]
pub struct OrderLines {
    lines: Vec<OrderLine>,
}

impl OrderLines {
    pub fn new(lines: Vec<OrderLine>) -> Self {
        Self { lines }
    }

    pub fn len(&self) -> usize {
        self.lines.len()
    }

    pub fn is_empty(&self) -> bool {
        self.lines.is_empty()
    }
}

// Continue from the previous lesson.
// TODO: add iter(&self).

use rust_daily_lesson::{OrderLine, OrderLines};

#[test]
fn iter_borrows_lines() {
    let lines = OrderLines::new(vec![OrderLine {
        sku: "A".to_owned(),
        quantity: 2,
    }]);
    let skus: Vec<_> = lines.iter().map(|line| line.sku.as_str()).collect();

    assert_eq!(skus, vec!["A"]);
}

